const DEFAULT_LABEL = "Coding agent";
/**
 * Short label for the host coding agent, embedded in template-preview
 * `editStarted` events so the browser can say who is editing. Override with
 * `BITFAB_AGENT_LABEL`.
 */
export function resolveCodingAgentDisplayName() {
    const override = process.env.BITFAB_AGENT_LABEL?.trim();
    if (override) {
        return override;
    }
    if (process.env.CODEX_THREAD_ID != null ||
        process.env.CODEX_CI === "1" ||
        process.env.CODEX_SANDBOX === "seatbelt") {
        return "Codex";
    }
    if (process.env.CLAUDE_CODE_VERSION != null) {
        return "Claude";
    }
    if (process.env.CURSOR_PLUGIN_ROOT != null) {
        return "Cursor";
    }
    return DEFAULT_LABEL;
}
